import { useState, useEffect, useRef } from 'react';

interface Program {
  program_id: number;
  title: string;
  description: string;
  category: string;
  start_time: string;
  end_time: string;
  rating: string;
}

interface ChannelGuide {
  channel_id: number;
  channel_name: string;
  logo_url: string | null;
  slug: string;
  programs: Program[];
}

interface Props {
  onChannelSelect: (channelId: number) => void;
  onProgramSelect: (program: Program, channelId: number) => void;
}

const HOUR_WIDTH = 240; // pixels per hour
const ROW_HEIGHT = 64;

export default function EPGGrid({ onChannelSelect, onProgramSelect }: Props) {
  const [guide, setGuide] = useState<ChannelGuide[]>([]);
  const [startTime, setStartTime] = useState('');
  const gridRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetch('/api/epg/guide?hours=8')
      .then(r => r.json())
      .then(data => {
        setGuide(data.guide);
        setStartTime(data.start);
      });
  }, []);

  const guideStart = new Date(startTime).getTime();

  const getProgramStyle = (prog: Program) => {
    const start = new Date(prog.start_time).getTime();
    const end = new Date(prog.end_time).getTime();
    const offsetMs = Math.max(0, start - guideStart);
    const durationMs = end - Math.max(start, guideStart);
    const leftPx = (offsetMs / 3600000) * HOUR_WIDTH;
    const widthPx = Math.max(40, (durationMs / 3600000) * HOUR_WIDTH);
    return { left: `${leftPx}px`, width: `${widthPx}px`, height: `${ROW_HEIGHT - 4}px` };
  };

  const isCurrentProgram = (prog: Program) => {
    const now = Date.now();
    return new Date(prog.start_time).getTime() <= now && new Date(prog.end_time).getTime() > now;
  };

  // Generate time ruler labels
  const timeLabels = [];
  for (let h = 0; h < 8; h++) {
    const t = new Date(guideStart + h * 3600000);
    timeLabels.push({ label: t.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }), left: h * HOUR_WIDTH });
  }

  return (
    <div className="epg-container">
      <div className="epg-time-ruler">
        {timeLabels.map((t, i) => (
          <div key={i} className="time-label" style={{ left: `${t.left}px` }}>{t.label}</div>
        ))}
      </div>
      <div className="epg-grid" ref={gridRef}>
        {guide.map(ch => (
          <div key={ch.channel_id} className="epg-row" style={{ height: `${ROW_HEIGHT}px` }}>
            <div className="epg-channel-label" onClick={() => onChannelSelect(ch.channel_id)}>
              {ch.logo_url && <img src={ch.logo_url} alt={ch.channel_name} className="channel-logo" />}
              <span>{ch.channel_name}</span>
            </div>
            <div className="epg-programs">
              {ch.programs.map(prog => (
                <div
                  key={prog.program_id}
                  className={`epg-program ${isCurrentProgram(prog) ? 'now' : ''}`}
                  style={getProgramStyle(prog)}
                  onClick={() => onProgramSelect(prog, ch.channel_id)}
                  title={`${prog.title}\n${prog.start_time} - ${prog.end_time}`}
                >
                  <span className="prog-title">{prog.title}</span>
                  <span className="prog-time">
                    {new Date(prog.start_time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

import { useState, useRef, useEffect, useCallback } from 'react';
import Hls from 'hls.js';

interface Channel {
  id: number;
  name: string;
  slug: string;
  logo_url: string | null;
  hls_url: string;
}

interface CurrentProgram {
  title: string;
  start_time: string;
  end_time: string;
  category: string;
}

interface Props {
  channels: Channel[];
  initialChannelId?: number;
}

export default function IPTVPlayer({ channels, initialChannelId }: Props) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const hlsRef = useRef<Hls | null>(null);
  const [currentChannel, setCurrentChannel] = useState<Channel | null>(null);
  const [qualities, setQualities] = useState<{ height: number; index: number }[]>([]);
  const [selectedQuality, setSelectedQuality] = useState(-1); // -1 = auto
  const [currentProgram, setCurrentProgram] = useState<CurrentProgram | null>(null);
  const [showOverlay, setShowOverlay] = useState(true);

  const loadChannel = useCallback((channel: Channel) => {
    const video = videoRef.current;
    if (!video) return;

    // Destroy existing HLS instance
    if (hlsRef.current) {
      hlsRef.current.destroy();
    }

    if (Hls.isSupported()) {
      const hls = new Hls({
        enableWorker: true,
        lowLatencyMode: true,
        maxBufferLength: 30,
        maxMaxBufferLength: 60,
      });
      hls.loadSource(channel.hls_url);
      hls.attachMedia(video);

      hls.on(Hls.Events.MANIFEST_PARSED, (_event, data) => {
        const levels = data.levels.map((level, index) => ({
          height: level.height, index
        }));
        setQualities(levels);
        setSelectedQuality(-1);
        video.play().catch(console.error);
      });

      hls.on(Hls.Events.ERROR, (_event, data) => {
        if (data.fatal) {
          if (data.type === Hls.ErrorTypes.NETWORK_ERROR) {
            hls.startLoad();
          } else if (data.type === Hls.ErrorTypes.MEDIA_ERROR) {
            hls.recoverMediaError();
          }
        }
      });

      hlsRef.current = hls;
    } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
      // Native HLS support (Safari)
      video.src = channel.hls_url;
      video.play().catch(console.error);
    }

    setCurrentChannel(channel);

    // Fetch current program for this channel
    fetch(`/api/epg/channel/${channel.id}`)
      .then(r => r.json())
      .then(data => {
        const now = Date.now();
        const current = data.programs.find(
          (p: CurrentProgram) =>
            new Date(p.start_time).getTime() <= now && new Date(p.end_time).getTime() > now
        );
        setCurrentProgram(current || null);
      });
  }, []);

  useEffect(() => {
    const initial = channels.find(c => c.id === initialChannelId) || channels[0];
    if (initial) loadChannel(initial);
    return () => { hlsRef.current?.destroy(); };
  }, []);

  const changeQuality = (index: number) => {
    if (hlsRef.current) {
      hlsRef.current.currentLevel = index; // -1 for auto
      setSelectedQuality(index);
    }
  };

  const togglePiP = async () => {
    const video = videoRef.current;
    if (!video) return;
    if (document.pictureInPictureElement) {
      await document.exitPictureInPicture();
    } else {
      await video.requestPictureInPicture();
    }
  };

  const channelUp = () => {
    if (!currentChannel) return;
    const idx = channels.findIndex(c => c.id === currentChannel.id);
    const next = channels[(idx + 1) % channels.length];
    loadChannel(next);
  };

  const channelDown = () => {
    if (!currentChannel) return;
    const idx = channels.findIndex(c => c.id === currentChannel.id);
    const prev = channels[(idx - 1 + channels.length) % channels.length];
    loadChannel(prev);
  };

  return (
    <div className="iptv-player" onMouseMove={() => setShowOverlay(true)}>
      <video ref={videoRef} className="player-video" playsInline />

      {showOverlay && currentChannel && (
        <div className="player-overlay">
          <div className="channel-info">
            {currentChannel.logo_url && (
              <img src={currentChannel.logo_url} alt="" className="overlay-logo" />
            )}
            <span className="channel-name">{currentChannel.name}</span>
            {currentProgram && (
              <span className="program-name">{currentProgram.title}</span>
            )}
          </div>

          <div className="player-controls">
            <button onClick={channelDown} title="Previous channel">CH-</button>
            <button onClick={channelUp} title="Next channel">CH+</button>

            <select value={selectedQuality}
              onChange={e => changeQuality(parseInt(e.target.value))}>
              <option value={-1}>Auto</option>
              {qualities.map(q => (
                <option key={q.index} value={q.index}>{q.height}p</option>
              ))}
            </select>

            <button onClick={togglePiP} title="Picture in Picture">PiP</button>
          </div>
        </div>
      )}
    </div>
  );
}

