@media (max-width: 640px) {
  .player-overlay { flex-direction: column; }
  .channel-info { font-size: 0.85rem; }
  .epg-container { display: none; }
  .channel-list { position: fixed; bottom: 0; width: 100%; }
}

/* Tablet: side-by-side with mini guide */
@media (min-width: 641px) and (max-width: 1024px) {
  .iptv-layout { display: grid; grid-template-columns: 1fr 280px; }
}

/* Desktop/TV: full guide visible */
@media (min-width: 1025px) {
  .iptv-layout { display: grid; grid-template-columns: 1fr 360px; }
  .epg-container { max-height: calc(100vh - 80px); overflow-y: auto; }
}

/* Smart TV: large text, d-pad friendly focus states */
@media (min-width: 1920px) {
  .channel-name { font-size: 1.5rem; }
  .epg-program:focus { outline: 3px solid #e94560; transform: scale(1.02); }
  button:focus { outline: 3px solid #e94560; }
}
